package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.math.*;import java.sql.*;import java.util.*;/** Row-locked transactional offline payment and whole-payment refund workflow. */public class PaymentServiceImpl implements PaymentService{private static final Logger LOG=LoggerFactory.getLogger(PaymentServiceImpl.class);private final PaymentDao payments;private final BillDao bills;private final BillingCalculator calc;private final PaymentValidator validator;private final PaymentNumberGenerator numbers;private final AuditLogDao audit;private final BillService billService;public PaymentServiceImpl(){this(new PaymentDaoImpl(),new BillDaoImpl(),new BillingCalculator(),new PaymentValidator(),new PaymentNumberGenerator(),new AuditLogDaoImpl(),new BillServiceImpl());}public PaymentServiceImpl(PaymentDao p,BillDao b,BillingCalculator c,PaymentValidator v,PaymentNumberGenerator n,AuditLogDao a,BillService bs){payments=p;bills=b;calc=c;validator=v;numbers=n;audit=a;billService=bs;}public List<Payment>listPayments(Long id,AuthenticatedUser u){if(billService.getBill(id,u).isEmpty())return List.of();try{return payments.findByBillId(id);}catch(SQLException e){return List.of();}}public Optional<Payment>getPayment(Long id,AuthenticatedUser u){try{Payment p=payments.findById(id).orElse(null);return p!=null&&billService.getBill(p.getBillId(),u).isPresent()?Optional.of(p):Optional.empty();}catch(SQLException e){return Optional.empty();}}
public ServiceResult<Long>recordPayment(PaymentForm f,AuditContext a,AuthenticatedUser u){if(!canRecord(u,f)){event("PAYMENT_ACCESS_DENIED",null,a);return failL(ServiceResult.Status.FORBIDDEN,"Payment access denied");}if(f==null||f.getBillId()==null)return failL(ServiceResult.Status.VALIDATION_ERROR,"Invalid bill");try{long id=tx(c->{Bill b=bills.findByIdForUpdate(c,f.getBillId()).orElse(null);if(b==null)throw new Business(ServiceResult.Status.NOT_FOUND,"Bill not found",Map.of());if(Set.of("PAID","CANCELLED","REFUNDED").contains(b.getStatus()))throw new Business(ServiceResult.Status.CONFLICT,"This bill cannot accept payments",Map.of());ValidationResult v=validator.validate(f,b.getBalanceAmount());if(v.hasErrors())throw new Business(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());Payment p=new Payment();p.setPaymentNumber(numbers.next(c));p.setBillId(b.getBillId());p.setAmount(new BigDecimal(f.getAmount().trim()).setScale(2,RoundingMode.HALF_UP));p.setPaymentMethod(f.getPaymentMethod().trim().toUpperCase());p.setTransactionReference(trim(f.getTransactionReference()));p.setStatus("SUCCESS");p.setReceivedBy(u.getUserId());long x=payments.createPayment(c,p);BigDecimal paid=payments.calculateSuccessfulPaidAmount(c,b.getBillId()),balance=calc.calculateBalance(b.getTotalAmount(),paid);String st=calc.deriveBillStatus(b.getTotalAmount(),paid,b.getStatus());if(!bills.updateFinancialSummary(c,b.getBillId(),b.getSubtotal(),b.getTaxAmount(),b.getDiscountAmount(),b.getTotalAmount(),paid,balance,st))throw new SQLException("Bill summary update failed");return x;});event("PAYMENT_RECORDED",id,a);return ServiceResult.success("Payment recorded",id);}catch(Business e){event("PAYMENT_BLOCKED",null,a);return ServiceResult.failure(e.status,e.getMessage(),e.errors);}catch(SQLException|IllegalArgumentException e){LOG.error("Payment recording failed",e);return failL(ServiceResult.Status.SYSTEM_ERROR,"Payment service is temporarily unavailable");}}
public ServiceResult<Void>refundPayment(Long id,AuditContext a,AuthenticatedUser u){if(u==null||!"ADMIN".equals(u.getRoleName())){event("PAYMENT_ACCESS_DENIED",id,a);return fail(ServiceResult.Status.FORBIDDEN,"Only an administrator may refund payments");}try{tx(c->{Payment p=payments.findById(c,id).orElse(null);if(p==null)throw new Business(ServiceResult.Status.NOT_FOUND,"Payment not found",Map.of());if(!"SUCCESS".equals(p.getStatus()))throw new Business(ServiceResult.Status.CONFLICT,"Payment has already been refunded",Map.of());Bill b=bills.findByIdForUpdate(c,p.getBillId()).orElse(null);if(b==null)throw new Business(ServiceResult.Status.NOT_FOUND,"Bill not found",Map.of());payments.updateStatus(c,id,"REFUNDED");BigDecimal paid=payments.calculateSuccessfulPaidAmount(c,b.getBillId()),balance=calc.calculateBalance(b.getTotalAmount(),paid);String st=paid.signum()==0?"REFUNDED":calc.deriveBillStatus(b.getTotalAmount(),paid,"UNPAID");bills.updateFinancialSummary(c,b.getBillId(),b.getSubtotal(),b.getTaxAmount(),b.getDiscountAmount(),b.getTotalAmount(),paid,balance,st);return null;});event("PAYMENT_REFUNDED",id,a);return ServiceResult.success("Payment refunded",null);}catch(Business e){event("PAYMENT_BLOCKED",id,a);return ServiceResult.failure(e.status,e.getMessage(),e.errors);}catch(SQLException e){LOG.error("Payment refund failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Payment service is temporarily unavailable");}}
private boolean canRecord(AuthenticatedUser u,PaymentForm f){if(u==null)return false;if(Set.of("ADMIN","BILLING_STAFF").contains(u.getRoleName()))return true;return"RECEPTIONIST".equals(u.getRoleName())&&f!=null&&"CASH".equalsIgnoreCase(f.getPaymentMethod());}private String trim(String s){return s==null?null:s.trim();}private<T>T tx(Work<T>w)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){boolean old=c.getAutoCommit();c.setAutoCommit(false);try{T v=w.run(c);c.commit();return v;}catch(SQLException|RuntimeException e){c.rollback();throw e;}finally{c.setAutoCommit(old);}}}private interface Work<T>{T run(Connection c)throws SQLException;}private void event(String e,Long id,AuditContext x){try{AuditContext a=x==null?new AuditContext(null,null,null):x;audit.recordEvent(e,a.userId(),"PAYMENT",id,a.ipAddress(),a.userAgent());}catch(RuntimeException z){LOG.warn("Payment audit failed: {}",e,z);}}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private static class Business extends RuntimeException{final ServiceResult.Status status;final Map<String,String>errors;Business(ServiceResult.Status s,String m,Map<String,String>e){super(m);status=s;errors=e;}}}
